var Emitter = require('events').EventEmitter;
var util = require('util');
var path = require('path');
var fs = require('fs');
var jade = require('jade');

var Stage = function (options) {
  // body...
};

util.inherits(Stage, Emitter);

Stage.prototype.middleware = function () {
  return function (req, res, next) {
    var result;
    if (req.url.indexOf('index') > -1) {
      result = fs.readFileSync(path.join(__dirname, '../stage/index.jade'));
      result = new Buffer(
        jade.compile(result, {filename: 'index', pretty: false})({}).trim());
    }else if (req.url.indexOf('runtimelog') > -1) {
      result = fs.readFileSync(path.join(__dirname, '../stage/runtimelog.jade'));
      result = new Buffer(
        jade.compile(result, {filename: 'runtimelog', pretty: false})({}).trim());
    } else {
      result = '{"user" : {"username" : "zx"}}';
    }
    res.end(result);
  };
};

module.exports = function (options) {
  return new Stage(options);
};